import numpy as np

def gd_quadratic(w0, eta, steps, w_star=3.0):
    w = w0
    for _ in range(steps):
        grad = 2 * (w - w_star)  # d/dw (w - w_star)^2
        w = w - eta * grad
    return w

for eta in [0.05, 0.5, 1.1]:
    w_final = gd_quadratic(w0=0.0, eta=eta, steps=20)
    print(f"eta={eta:.2f} -> w={w_final:.4f} (target 3.0)")
